   104→// CorruptionErr is an error that's returned when corruption is encountered.
   105→type CorruptionErr struct {
   106→	Dir     string
   107→	Segment int
   108→	Offset  int64
   109→	Err     error
   110→}
   111→
   112→func (e *CorruptionErr) Error() string {
   113→	if e.Segment < 0 {
   114→		return fmt.Sprintf("corruption after %d bytes: %s", e.Offset, e.Err)
   115→	}
   116→	return fmt.Sprintf("corruption in segment %s at %d: %s", SegmentName(e.Dir, e.Segment), e.Offset, e.Err)
   117→}
   118→
   119→func (e *CorruptionErr) Unwrap() error {
   120→	return e.Err
   121→}
   122→
   123→// OpenWriteSegment opens segment k in dir. The returned segment is ready for new appends.
   124→func OpenWriteSegment(logger *slog.Logger, dir string, k int) (*Segment, error) {
   125→	segName := SegmentName(dir, k)
   126→	f, err := os.OpenFile(segName, os.O_WRONLY|os.O_APPEND, 0o666)
   127→	if err != nil {
   128→		return nil, err
   129→	}
   130→	stat, err := f.Stat()
   131→	if err != nil {
   132→		f.Close()
   133→		return nil, err
   134→	}
   135→	// If the last page is torn, fill it with zeros.
   136→	// In case it was torn after all records were written successfully, this
   137→	// will just pad the page and everything will be fine.
   138→	// If it was torn mid-record, a full read (which the caller should do anyway
   139→	// to ensure integrity) will detect it as a corruption by the end.
   140→	if d := stat.Size() % pageSize; d != 0 {
   141→		logger.Warn("Last page of the wlog is torn, filling it with zeros", "segment", segName)
   142→		if _, err := f.Write(make([]byte, pageSize-d)); err != nil {
   143→			f.Close()
   144→			return nil, fmt.Errorf("zero-pad torn page: %w", err)
   145→		}
   146→	}
   147→	return &Segment{SegmentFile: f, i: k, dir: dir}, nil
   148→}
   149→
   150→// CreateSegment creates a new segment k in dir.
   151→func CreateSegment(dir string, k int) (*Segment, error) {
   152→	f, err := os.OpenFile(SegmentName(dir, k), os.O_WRONLY|os.O_CREATE|os.O_APPEND, 0o666)
   153→	if err != nil {
   154→		return nil, err
   155→	}
   156→	return &Segment{SegmentFile: f, i: k, dir: dir}, nil
   157→}
   158→
   159→// OpenReadSegment opens the segment with the given filename.
   160→func OpenReadSegment(fn string) (*Segment, error) {
   161→	k, err := strconv.Atoi(filepath.Base(fn))
   162→	if err != nil {
   163→		return nil, errors.New("not a valid filename")
   164→	}
   165→	f, err := os.Open(fn)
   166→	if err != nil {
   167→		return nil, err
   168→	}
   169→	return &Segment{SegmentFile: f, i: k, dir: filepath.Dir(fn)}, nil
   170→}
