   293→// New returns a new WAL over the given directory.
   294→func New(logger *slog.Logger, reg prometheus.Registerer, dir string, compress compression.Type) (*WL, error) {
   295→	return NewSize(logger, reg, dir, DefaultSegmentSize, compress)
   296→}
   297→
   298→// NewSize returns a new write log over the given directory.
   299→// New segments are created with the specified size.
   300→func NewSize(logger *slog.Logger, reg prometheus.Registerer, dir string, segmentSize int, compress compression.Type) (*WL, error) {
   301→	if segmentSize%pageSize != 0 {
   302→		return nil, errors.New("invalid segment size")
   303→	}
   304→	if err := os.MkdirAll(dir, 0o777); err != nil {
   305→		return nil, fmt.Errorf("create dir: %w", err)
   306→	}
   307→	if logger == nil {
   308→		logger = promslog.NewNopLogger()
   309→	}
   310→
   311→	w := &WL{
   312→		dir:         dir,
   313→		logger:      logger,
   314→		segmentSize: segmentSize,
   315→		page:        &page{},
   316→		actorc:      make(chan func(), 100),
   317→		stopc:       make(chan chan struct{}),
   318→		compress:    compress,
   319→		cEnc:        compression.NewSyncEncodeBuffer(),
   320→	}
   321→	prefix := "prometheus_tsdb_wal_"
   322→	if filepath.Base(dir) == WblDirName {
   323→		prefix = "prometheus_tsdb_out_of_order_wbl_"
   324→	}
   325→	w.metrics = newWLMetrics(w, prometheus.WrapRegistererWithPrefix(prefix, reg))
   326→
   327→	_, last, err := Segments(w.Dir())
   328→	if err != nil {
   329→		return nil, fmt.Errorf("get segment range: %w", err)
   330→	}
   331→
   332→	// Index of the Segment we want to open and write to.
   333→	writeSegmentIndex := 0
   334→	// If some segments already exist create one with a higher index than the last segment.
   335→	if last != -1 {
   336→		writeSegmentIndex = last + 1
   337→	}
   338→
   339→	segment, err := CreateSegment(w.Dir(), writeSegmentIndex)
   340→	if err != nil {
   341→		return nil, err
   342→	}
   343→
   344→	if err := w.setSegment(segment); err != nil {
   345→		return nil, err
   346→	}
   347→
   348→	go w.run()
   349→
   350→	return w, nil
   351→}
   352→
   353→// Open an existing WAL.
   354→func Open(logger *slog.Logger, dir string) (*WL, error) {
   355→	if logger == nil {
   356→		logger = promslog.NewNopLogger()
   357→	}
   358→
   359→	w := &WL{
   360→		dir:    dir,
   361→		logger: logger,
   362→	}
   363→	return w, nil
   364→}
   365→
   366→// CompressionType returns if compression is enabled on this WAL.
   367→func (w *WL) CompressionType() compression.Type {
   368→	return w.compress
   369→}
   370→
   371→// Dir returns the directory of the WAL.
   372→func (w *WL) Dir() string {
   373→	return w.dir
   374→}
   375→
   376→func (w *WL) SetWriteNotified(wn WriteNotified) {
   377→	w.WriteNotified = wn
   378→}
   379→
   380→func (w *WL) run() {
   381→Loop:
   382→	for {
   383→		select {
   384→		case f := <-w.actorc:
   385→			f()
   386→		case donec := <-w.stopc:
   387→			close(w.actorc)
   388→			defer close(donec)
   389→			break Loop
   390→		}
   391→	}
   392→	// Drain and process any remaining functions.
   393→	for f := range w.actorc {
   394→		f()
   395→	}
   396→}
   397→
   398→// Repair attempts to repair the WAL based on the error.
   399→// It discards all data after the corruption.
   400→func (w *WL) Repair(origErr error) error {
   401→	// We could probably have a mode that only discards torn records right around
   402→	// the corruption to preserve as data much as possible.
   403→	// But that's not generally applicable if the records have any kind of causality.
   404→	// Maybe as an extra mode in the future if mid-WAL corruptions become
   405→	// a frequent concern.
   406→	var cerr *CorruptionErr
   407→	if !errors.As(origErr, &cerr) {
   408→		return fmt.Errorf("cannot handle error: %w", origErr)
   409→	}
   410→	if cerr.Segment < 0 {
   411→		return errors.New("corruption error does not specify position")
   412→	}
   413→	w.logger.Warn("Starting corruption repair",
   414→		"segment", cerr.Segment, "offset", cerr.Offset)
   415→
   416→	// All segments behind the corruption can no longer be used.
   417→	segs, err := listSegments(w.Dir())
   418→	if err != nil {
   419→		return fmt.Errorf("list segments: %w", err)
   420→	}
   421→	w.logger.Warn("Deleting all segments newer than corrupted segment", "segment", cerr.Segment)
   422→
   423→	for _, s := range segs {
   424→		if w.segment.i == s.index {
   425→			// The active segment needs to be removed,
   426→			// close it first (Windows!). Can be closed safely
   427→			// as we set the current segment to repaired file
   428→			// below.
   429→			if err := w.segment.Close(); err != nil {
   430→				return fmt.Errorf("close active segment: %w", err)
   431→			}
   432→		}
   433→		if s.index <= cerr.Segment {
   434→			continue
   435→		}
   436→		if err := os.Remove(filepath.Join(w.Dir(), s.name)); err != nil {
   437→			return fmt.Errorf("delete segment:%v: %w", s.index, err)
   438→		}
   439→	}
   440→	// Regardless of the corruption offset, no record reaches into the previous segment.
   441→	// So we can safely repair the WAL by removing the segment and re-inserting all
   442→	// its records up to the corruption.
   443→	w.logger.Warn("Rewrite corrupted segment", "segment", cerr.Segment)
   444→
   445→	fn := SegmentName(w.Dir(), cerr.Segment)
   446→	tmpfn := fn + ".repair"
   447→
   448→	if err := fileutil.Rename(fn, tmpfn); err != nil {
   449→		return err
   450→	}
   451→	// Create a clean segment and make it the active one.
   452→	s, err := CreateSegment(w.Dir(), cerr.Segment)
   453→	if err != nil {
   454→		return err
   455→	}
   456→	if err := w.setSegment(s); err != nil {
   457→		return err
   458→	}
   459→
   460→	f, err := os.Open(tmpfn)
   461→	if err != nil {
   462→		return fmt.Errorf("open segment: %w", err)
   463→	}
   464→	defer f.Close()
   465→
   466→	r := NewReader(bufio.NewReader(f))
   467→
   468→	for r.Next() {
   469→		// Add records only up to the where the error was.
   470→		if r.Offset() >= cerr.Offset {
   471→			break
   472→		}
   473→		if err := w.Log(r.Record()); err != nil {
   474→			return fmt.Errorf("insert record: %w", err)
   475→		}
   476→	}
   477→	// We expect an error here from r.Err(), so nothing to handle.
   478→
   479→	// We need to pad to the end of the last page in the repaired segment
   480→	if err := w.flushPage(true); err != nil {
   481→		return fmt.Errorf("flush page in repair: %w", err)
   482→	}
   483→
   484→	// We explicitly close even when there is a defer for Windows to be
   485→	// able to delete it. The defer is in place to close it in-case there
   486→	// are errors above.
   487→	if err := f.Close(); err != nil {
   488→		return fmt.Errorf("close corrupted file: %w", err)
   489→	}
   490→	if err := os.Remove(tmpfn); err != nil {
   491→		return fmt.Errorf("delete corrupted segment: %w", err)
   492→	}
   493→
   494→	// Explicitly close the segment we just repaired to avoid issues with Windows.
   495→	s.Close()
   496→
   497→	// We always want to start writing to a new Segment rather than an existing
   498→	// Segment, which is handled by NewSize, but earlier in Repair we're deleting
   499→	// all segments that come after the corrupted Segment. Recreate a new Segment here.
   500→	s, err = CreateSegment(w.Dir(), cerr.Segment+1)
   501→	if err != nil {
   502→		return err
   503→	}
   504→	return w.setSegment(s)
   505→}
   506→
   507→// SegmentName builds a segment name for the directory.
   508→func SegmentName(dir string, i int) string {
   509→	return filepath.Join(dir, fmt.Sprintf("%08d", i))
   510→}
   511→
   512→// NextSegment creates the next segment and closes the previous one asynchronously.
   513→// It returns the file number of the new file.
   514→func (w *WL) NextSegment() (int, error) {
   515→	w.mtx.Lock()
   516→	defer w.mtx.Unlock()
   517→	return w.nextSegment(true)
   518→}
   519→
   520→// NextSegmentSync creates the next segment and closes the previous one in sync.
   521→// It returns the file number of the new file.
   522→func (w *WL) NextSegmentSync() (int, error) {
   523→	w.mtx.Lock()
   524→	defer w.mtx.Unlock()
   525→	return w.nextSegment(false)
   526→}
   527→
   528→// nextSegment creates the next segment and closes the previous one.
   529→// It returns the file number of the new file.
   530→func (w *WL) nextSegment(async bool) (int, error) {
   531→	if w.closed {
   532→		return 0, errors.New("wlog is closed")
   533→	}
   534→
   535→	// Only flush the current page if it actually holds data.
   536→	if w.page.alloc > 0 {
   537→		if err := w.flushPage(true); err != nil {
   538→			return 0, err
   539→		}
   540→	}
   541→	next, err := CreateSegment(w.Dir(), w.segment.Index()+1)
   542→	if err != nil {
   543→		return 0, fmt.Errorf("create new segment file: %w", err)
   544→	}
   545→	prev := w.segment
   546→	if err := w.setSegment(next); err != nil {
   547→		return 0, err
   548→	}
   549→
   550→	// Don't block further writes by fsyncing the last segment.
   551→	f := func() {
   552→		if err := w.fsync(prev); err != nil {
   553→			w.logger.Error("sync previous segment", "err", err)
   554→		}
   555→		if err := prev.Close(); err != nil {
   556→			w.logger.Error("close previous segment", "err", err)
   557→		}
   558→	}
   559→	if async {
   560→		w.actorc <- f
   561→	} else {
   562→		f()
   563→	}
   564→	return next.Index(), nil
   565→}
   566→
   567→func (w *WL) setSegment(segment *Segment) error {
   568→	w.segment = segment
   569→
   570→	// Correctly initialize donePages.
   571→	stat, err := segment.Stat()
   572→	if err != nil {
   573→		return err
   574→	}
   575→	w.donePages = int(stat.Size() / pageSize)
   576→	w.metrics.currentSegment.Set(float64(segment.Index()))
   577→	return nil
   578→}
   579→
   580→// flushPage writes the new contents of the page to disk. If no more records will fit into
   581→// the page, the remaining bytes will be set to zero and a new page will be started.
   582→// If forceClear is true, this is enforced regardless of how many bytes are left in the page.
   583→func (w *WL) flushPage(forceClear bool) error {
   584→	w.metrics.pageFlushes.Inc()
   585→
   586→	p := w.page
   587→	shouldClear := forceClear || p.full()
   588→
   589→	// No more data will fit into the page or an implicit clear.
   590→	// Enqueue and clear it.
   591→	if shouldClear {
   592→		p.alloc = pageSize // Write till end of page.
   593→	}
   594→
   595→	n, err := w.segment.Write(p.buf[p.flushed:p.alloc])
   596→	if err != nil {
   597→		p.flushed += n
   598→		return err
   599→	}
   600→	p.flushed += n
   601→
   602→	// We flushed an entire page, prepare a new one.
   603→	if shouldClear {
   604→		p.reset()
   605→		w.donePages++
   606→		w.metrics.pageCompletions.Inc()
   607→	}
   608→	return nil
   609→}
