   655→// Log writes the records into the log.
   656→// Multiple records can be passed at once to reduce writes and increase throughput.
   657→func (w *WL) Log(recs ...[]byte) error {
   658→	w.mtx.Lock()
   659→	defer w.mtx.Unlock()
   660→	// Callers could just implement their own list record format but adding
   661→	// a bit of extra logic here frees them from that overhead.
   662→	for i, r := range recs {
   663→		if err := w.log(r, i == len(recs)-1); err != nil {
   664→			w.metrics.writesFailed.Inc()
   665→			return err
   666→		}
   667→	}
   668→	return nil
   669→}
