   671→// log writes rec to the log and forces a flush of the current page if:
   672→// - the final record of a batch
   673→// - the record is bigger than the page size
   674→// - the current page is full.
   675→func (w *WL) log(rec []byte, final bool) error {
   676→	// When the last page flush failed the page will remain full.
   677→	// When the page is full, need to flush it before trying to add more records to it.
   678→	if w.page.full() {
   679→		if err := w.flushPage(true); err != nil {
   680→			return err
   681→		}
   682→	}
   683→
   684→	// Compress the record before calculating if a new segment is needed.
   685→	finalCompression := w.compress
   686→	enc, err := compression.Encode(w.compress, rec, w.cEnc)
   687→	if err != nil {
   688→		return err
   689→	}
   690→	if w.compress != compression.None {
   691→		savedBytes := len(rec) - len(enc)
   692→
   693→		// Even if the compression was applied, skip it, if there's no benefit
   694→		// in the WAL record size (we have a choice). For small records e.g. snappy
   695→		// compression can yield larger records than the uncompressed.
   696→		if savedBytes <= 0 {
   697→			enc = rec
   698→			finalCompression = compression.None
   699→			savedBytes = 0
   700→		}
   701→		w.metrics.recordBytesSaved.WithLabelValues(w.compress).Add(float64(savedBytes))
   702→	}
   703→
   704→	// If the record is too big to fit within the active page in the current
   705→	// segment, terminate the active segment and advance to the next one.
   706→	// This ensures that records do not cross segment boundaries.
   707→	left := w.page.remaining() - recordHeaderSize                                   // Free space in the active page.
   708→	left += (pageSize - recordHeaderSize) * (w.pagesPerSegment() - w.donePages - 1) // Free pages in the active segment.
   709→
   710→	if len(enc) > left {
   711→		if _, err := w.nextSegment(true); err != nil {
   712→			return err
   713→		}
   714→	}
   715→
   716→	// Populate as many pages as necessary to fit the record.
   717→	// Be careful to always do one pass to ensure we write zero-length records.
   718→	for i := 0; i == 0 || len(enc) > 0; i++ {
   719→		p := w.page
   720→
   721→		// Find how much of the record we can fit into the page.
   722→		var (
   723→			l    = min(len(enc), (pageSize-p.alloc)-recordHeaderSize)
   724→			part = enc[:l]
   725→			buf  = p.buf[p.alloc:]
   726→			typ  recType
   727→		)
   728→
   729→		switch {
   730→		case i == 0 && len(part) == len(enc):
   731→			typ = recFull
   732→		case len(part) == len(enc):
   733→			typ = recLast
   734→		case i == 0:
   735→			typ = recFirst
   736→		default:
   737→			typ = recMiddle
   738→		}
   739→
   740→		if finalCompression != compression.None {
   741→			switch finalCompression {
   742→			case compression.Snappy:
   743→				typ |= snappyMask
   744→			case compression.Zstd:
   745→				typ |= zstdMask
   746→			default:
   747→				return fmt.Errorf("unsupported compression type: %v", finalCompression)
   748→			}
   749→		}
   750→
   751→		buf[0] = byte(typ)
   752→		crc := crc32.Checksum(part, castagnoliTable)
   753→		binary.BigEndian.PutUint16(buf[1:], uint16(len(part)))
   754→		binary.BigEndian.PutUint32(buf[3:], crc)
   755→
   756→		copy(buf[recordHeaderSize:], part)
   757→		p.alloc += len(part) + recordHeaderSize
   758→
   759→		w.metrics.recordPartWrites.Inc()
   760→		w.metrics.recordPartBytes.Add(float64(len(part) + recordHeaderSize))
   761→
   762→		if w.page.full() {
   763→			if err := w.flushPage(true); err != nil {
   764→				// TODO When the flushing fails at this point and the record has not been
   765→				// fully written to the buffer, we end up with a corrupted WAL because some part of the
   766→				// record have been written to the buffer, while the rest of the record will be discarded.
   767→				return err
   768→			}
   769→		}
   770→		enc = enc[l:]
   771→	}
   772→
   773→	// If it's the final record of the batch and the page is not empty, flush it.
   774→	if final && w.page.alloc > 0 {
   775→		if err := w.flushPage(false); err != nil {
   776→			return err
   777→		}
   778→	}
   779→
   780→	return nil
   781→}
