   783→// LastSegmentAndOffset returns the last segment number of the WAL
   784→// and the offset in that file upto which the segment has been filled.
   785→func (w *WL) LastSegmentAndOffset() (seg, offset int, err error) {
   786→	w.mtx.Lock()
   787→	defer w.mtx.Unlock()
   788→
   789→	_, seg, err = Segments(w.Dir())
   790→	if err != nil {
   791→		return seg, offset, err
