   836→// Close flushes all writes and closes active segment.
   837→func (w *WL) Close() (err error) {
   838→	w.mtx.Lock()
   839→	defer w.mtx.Unlock()
   840→
   841→	if w.closed {
   842→		return errors.New("wlog already closed")
   843→	}
   844→
   845→	if w.segment == nil {
   846→		w.closed = true
   847→		return nil
   848→	}
   849→
   850→	// Flush the last page and zero out all its remaining size.
   851→	// We must not flush an empty page as it would falsely signal
   852→	// the segment is done if we start writing to it again after opening.
   853→	if w.page.alloc > 0 {
   854→		if err := w.flushPage(true); err != nil {
   855→			return err
   856→		}
   857→	}
   858→
   859→	donec := make(chan struct{})
   860→	w.stopc <- donec
   861→	<-donec
   862→
   863→	if err = w.fsync(w.segment); err != nil {
   864→		w.logger.Error("sync previous segment", "err", err)
   865→	}
   866→	if err := w.segment.Close(); err != nil {
   867→		w.logger.Error("close previous segment", "err", err)
   868→	}
   869→
   870→	w.metrics.Unregister()
   871→	w.closed = true
   872→	return nil
   873→}
