   875→// Segments returns the range [first, n] of currently existing segments.
   876→// If no segments are found, first and n are -1.
   877→func Segments(wlDir string) (first, last int, err error) {
   878→	refs, err := listSegments(wlDir)
   879→	if err != nil {
   880→		return 0, 0, err
   881→	}
   882→	if len(refs) == 0 {
   883→		return -1, -1, nil
   884→	}
   885→	return refs[0].index, refs[len(refs)-1].index, nil
