   932→
   933→	for _, sgmRange := range sr {
   934→		refs, err := listSegments(sgmRange.Dir)
   935→		if err != nil {
   936→			return nil, fmt.Errorf("list segment in dir:%v: %w", sgmRange.Dir, err)
   937→		}
   938→
   939→		for _, r := range refs {
   940→			if sgmRange.First >= 0 && r.index < sgmRange.First {
   941→				continue
   942→			}
   943→			if sgmRange.Last >= 0 && r.index > sgmRange.Last {
   944→				break
   945→			}
