   956→// segmentBufReader is a buffered reader that reads in multiples of pages.
   957→// The main purpose is that we are able to track segment and offset for
   958→// corruption reporting.  We have to be careful not to increment curr too
   959→// early, as it is used by Reader.Err() to tell Repair which segment is corrupt.
   960→// As such we pad the end of non-page align segments with zeros.
   961→type segmentBufReader struct {
   962→	buf  *bufio.Reader
   963→	segs []*Segment
   964→	cur  int // Index into segs.
   965→	off  int // Offset of read data into current segment.
   966→}
   967→
   968→func NewSegmentBufReader(segs ...*Segment) io.ReadCloser {
   969→	if len(segs) == 0 {
   970→		return &segmentBufReader{}
   971→	}
   972→
   973→	return &segmentBufReader{
   974→		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
   975→		segs: segs,
   976→	}
   977→}
   978→
   979→func NewSegmentBufReaderWithOffset(offset int, segs ...*Segment) (io.ReadCloser, error) {
   980→	if offset == 0 || len(segs) == 0 {
   981→		return NewSegmentBufReader(segs...), nil
   982→	}
   983→
   984→	sbr := &segmentBufReader{
   985→		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
   986→		segs: segs,
   987→	}
   988→	var err error
   989→	if offset > 0 {
   990→		_, err = sbr.buf.Discard(offset)
   991→	}
   992→	return sbr, err
   993→}
   994→
   995→func (r *segmentBufReader) Close() (err error) {
   996→	for _, s := range r.segs {
   997→		if e := s.Close(); e != nil {
   998→			err = e
   999→		}
  1000→	}
  1001→	return err
  1002→}
