   380→func (w *WL) run() {
   381→Loop:
   382→	for {
   383→		select {
   384→		case f := <-w.actorc:
   385→			f()
   386→		case donec := <-w.stopc:
   387→			close(w.actorc)
   388→			defer close(donec)
   389→			break Loop
   390→		}
   391→	}
   392→	// Drain and process any remaining functions.
   393→	for f := range w.actorc {
   394→		f()
   395→	}
   396→}
