   298→// NewSize returns a new write log over the given directory.
   299→// New segments are created with the specified size.
   300→func NewSize(logger *slog.Logger, reg prometheus.Registerer, dir string, segmentSize int, compress compression.Type) (*WL, error) {
   301→	if segmentSize%pageSize != 0 {
   302→		return nil, errors.New("invalid segment size")
   303→	}
   304→	if err := os.MkdirAll(dir, 0o777); err != nil {
   305→		return nil, fmt.Errorf("create dir: %w", err)
   306→	}
   307→	if logger == nil {
   308→		logger = promslog.NewNopLogger()
   309→	}
   310→
   311→	w := &WL{
   312→		dir:         dir,
   313→		logger:      logger,
   314→		segmentSize: segmentSize,
   315→		page:        &page{},
   316→		actorc:      make(chan func(), 100),
   317→		stopc:       make(chan chan struct{}),
   318→		compress:    compress,
   319→		cEnc:        compression.NewSyncEncodeBuffer(),
   320→	}
   321→	prefix := "prometheus_tsdb_wal_"
   322→	if filepath.Base(dir) == WblDirName {
   323→		prefix = "prometheus_tsdb_out_of_order_wbl_"
   324→	}
   325→	w.metrics = newWLMetrics(w, prometheus.WrapRegistererWithPrefix(prefix, reg))
   326→
   327→	_, last, err := Segments(w.Dir())
   328→	if err != nil {
   329→		return nil, fmt.Errorf("get segment range: %w", err)
   330→	}
   331→
   332→	// Index of the Segment we want to open and write to.
   333→	writeSegmentIndex := 0
   334→	// If some segments already exist create one with a higher index than the last segment.
   335→	if last != -1 {
   336→		writeSegmentIndex = last + 1
   337→	}
   338→
   339→	segment, err := CreateSegment(w.Dir(), writeSegmentIndex)
   340→	if err != nil {
   341→		return nil, err
   342→	}
   343→
   344→	if err := w.setSegment(segment); err != nil {
   345→		return nil, err
   346→	}
   347→
   348→	go w.run()
   349→
   350→	return w, nil
   351→}
