   551→	f := func() {
   552→		if err := w.fsync(prev); err != nil {
   553→			w.logger.Error("sync previous segment", "err", err)
   554→		}
   555→		if err := prev.Close(); err != nil {
   556→			w.logger.Error("close previous segment", "err", err)
   557→		}
   558→	}
   559→	if async {
   560→		w.actorc <- f
   561→	} else {
   562→		f()
   563→	}
   564→	return next.Index(), nil
   565→}
   566→
   567→func (w *WL) setSegment(segment *Segment) error {
   568→	w.segment = segment
   569→
   570→	// Correctly initialize donePages.
   571→	stat, err := segment.Stat()
   572→	if err != nil {
   573→		return err
   574→	}
   575→	w.donePages = int(stat.Size() / pageSize)
   576→	w.metrics.currentSegment.Set(float64(segment.Index()))
   577→	return nil
   578→}
   579→
   580→// flushPage writes the new contents of the page to disk. If no more records will fit into
   581→// the page, the remaining bytes will be set to zero and a new page will be started.
   582→// If forceClear is true, this is enforced regardless of how many bytes are left in the page.
   583→func (w *WL) flushPage(forceClear bool) error {
   584→	w.metrics.pageFlushes.Inc()
   585→
   586→	p := w.page
   587→	shouldClear := forceClear || p.full()
   588→
   589→	// No more data will fit into the page or an implicit clear.
   590→	// Enqueue and clear it.
   591→	if shouldClear {
   592→		p.alloc = pageSize // Write till end of page.
   593→	}
   594→
   595→	n, err := w.segment.Write(p.buf[p.flushed:p.alloc])
   596→	if err != nil {
   597→		p.flushed += n
   598→		return err
   599→	}
   600→	p.flushed += n
   601→
   602→	// We flushed an entire page, prepare a new one.
   603→	if shouldClear {
   604→		p.reset()
   605→		w.donePages++
   606→		w.metrics.pageCompletions.Inc()
   607→	}
   608→	return nil
   609→}
   610→
   611→// First Byte of header format:
   612→//
   613→//	[3 bits unallocated] [1 bit zstd compression flag] [1 bit snappy compression flag] [3 bit record type ]
   614→const (
   615→	snappyMask  = 1 << 3
   616→	zstdMask    = 1 << 4
   617→	recTypeMask = snappyMask - 1
   618→)
   619→
   620→type recType uint8
   621→
   622→const (
   623→	recPageTerm recType = 0 // Rest of page is empty.
   624→	recFull     recType = 1 // Full record.
   625→	recFirst    recType = 2 // First fragment of a record.
   626→	recMiddle   recType = 3 // Middle fragments of a record.
   627→	recLast     recType = 4 // Final fragment of a record.
   628→)
   629→
   630→func recTypeFromHeader(header byte) recType {
   631→	return recType(header & recTypeMask)
   632→}
   633→
   634→func (t recType) String() string {
   635→	switch t {
   636→	case recPageTerm:
   637→		return "zero"
   638→	case recFull:
   639→		return "full"
   640→	case recFirst:
   641→		return "first"
   642→	case recMiddle:
   643→		return "middle"
   644→	case recLast:
   645→		return "last"
   646→	default:
   647→		return "<invalid>"
   648→	}
   649→}
   650→
   651→func (w *WL) pagesPerSegment() int {
   652→	return w.segmentSize / pageSize
   653→}
   654→
   655→// Log writes the records into the log.
   656→// Multiple records can be passed at once to reduce writes and increase throughput.
   657→func (w *WL) Log(recs ...[]byte) error {
   658→	w.mtx.Lock()
   659→	defer w.mtx.Unlock()
   660→	// Callers could just implement their own list record format but adding
   661→	// a bit of extra logic here frees them from that overhead.
   662→	for i, r := range recs {
   663→		if err := w.log(r, i == len(recs)-1); err != nil {
   664→			w.metrics.writesFailed.Inc()
   665→			return err
   666→		}
   667→	}
   668→	return nil
   669→}
   670→
   671→// log writes rec to the log and forces a flush of the current page if:
   672→// - the final record of a batch
   673→// - the record is bigger than the page size
   674→// - the current page is full.
   675→func (w *WL) log(rec []byte, final bool) error {
   676→	// When the last page flush failed the page will remain full.
   677→	// When the page is full, need to flush it before trying to add more records to it.
   678→	if w.page.full() {
   679→		if err := w.flushPage(true); err != nil {
   680→			return err
   681→		}
   682→	}
   683→
   684→	// Compress the record before calculating if a new segment is needed.
   685→	finalCompression := w.compress
   686→	enc, err := compression.Encode(w.compress, rec, w.cEnc)
   687→	if err != nil {
   688→		return err
   689→	}
   690→	if w.compress != compression.None {
   691→		savedBytes := len(rec) - len(enc)
   692→
   693→		// Even if the compression was applied, skip it, if there's no benefit
   694→		// in the WAL record size (we have a choice). For small records e.g. snappy
   695→		// compression can yield larger records than the uncompressed.
   696→		if savedBytes <= 0 {
   697→			enc = rec
   698→			finalCompression = compression.None
   699→			savedBytes = 0
   700→		}
   701→		w.metrics.recordBytesSaved.WithLabelValues(w.compress).Add(float64(savedBytes))
   702→	}
   703→
   704→	// If the record is too big to fit within the active page in the current
   705→	// segment, terminate the active segment and advance to the next one.
   706→	// This ensures that records do not cross segment boundaries.
   707→	left := w.page.remaining() - recordHeaderSize                                   // Free space in the active page.
   708→	left += (pageSize - recordHeaderSize) * (w.pagesPerSegment() - w.donePages - 1) // Free pages in the active segment.
   709→
   710→	if len(enc) > left {
   711→		if _, err := w.nextSegment(true); err != nil {
   712→			return err
   713→		}
   714→	}
   715→
   716→	// Populate as many pages as necessary to fit the record.
   717→	// Be careful to always do one pass to ensure we write zero-length records.
   718→	for i := 0; i == 0 || len(enc) > 0; i++ {
   719→		p := w.page
   720→
   721→		// Find how much of the record we can fit into the page.
   722→		var (
   723→			l    = min(len(enc), (pageSize-p.alloc)-recordHeaderSize)
   724→			part = enc[:l]
   725→			buf  = p.buf[p.alloc:]
   726→			typ  recType
   727→		)
   728→
   729→		switch {
   730→		case i == 0 && len(part) == len(enc):
   731→			typ = recFull
   732→		case len(part) == len(enc):
   733→			typ = recLast
   734→		case i == 0:
   735→			typ = recFirst
   736→		default:
   737→			typ = recMiddle
   738→		}
   739→
   740→		if finalCompression != compression.None {
   741→			switch finalCompression {
   742→			case compression.Snappy:
   743→				typ |= snappyMask
   744→			case compression.Zstd:
   745→				typ |= zstdMask
   746→			default:
   747→				return fmt.Errorf("unsupported compression type: %v", finalCompression)
   748→			}
   749→		}
   750→
   751→		buf[0] = byte(typ)
   752→		crc := crc32.Checksum(part, castagnoliTable)
   753→		binary.BigEndian.PutUint16(buf[1:], uint16(len(part)))
   754→		binary.BigEndian.PutUint32(buf[3:], crc)
   755→
   756→		copy(buf[recordHeaderSize:], part)
   757→		p.alloc += len(part) + recordHeaderSize
   758→
   759→		w.metrics.recordPartWrites.Inc()
   760→		w.metrics.recordPartBytes.Add(float64(len(part) + recordHeaderSize))
   761→
   762→		if w.page.full() {
   763→			if err := w.flushPage(true); err != nil {
   764→				// TODO When the flushing fails at this point and the record has not been
   765→				// fully written to the buffer, we end up with a corrupted WAL because some part of the
   766→				// record have been written to the buffer, while the rest of the record will be discarded.
   767→				return err
   768→			}
   769→		}
   770→		enc = enc[l:]
   771→	}
   772→
   773→	// If it's the final record of the batch and the page is not empty, flush it.
   774→	if final && w.page.alloc > 0 {
   775→		if err := w.flushPage(false); err != nil {
   776→			return err
   777→		}
   778→	}
   779→
   780→	return nil
   781→}
   782→
   783→// LastSegmentAndOffset returns the last segment number of the WAL
   784→// and the offset in that file upto which the segment has been filled.
   785→func (w *WL) LastSegmentAndOffset() (seg, offset int, err error) {
   786→	w.mtx.Lock()
   787→	defer w.mtx.Unlock()
   788→
   789→	_, seg, err = Segments(w.Dir())
   790→	if err != nil {
   791→		return seg, offset, err
   792→	}
   793→
   794→	offset = (w.donePages * pageSize) + w.page.alloc
   795→
   796→	return seg, offset, err
   797→}
   798→
   799→// Truncate drops all segments before i.
   800→func (w *WL) Truncate(i int) (err error) {
   801→	w.metrics.truncateTotal.Inc()
   802→	defer func() {
   803→		if err != nil {
   804→			w.metrics.truncateFail.Inc()
   805→		}
   806→	}()
   807→	refs, err := listSegments(w.Dir())
   808→	if err != nil {
   809→		return err
   810→	}
   811→	for _, r := range refs {
   812→		if r.index >= i {
   813→			break
   814→		}
   815→		if err = os.Remove(filepath.Join(w.Dir(), r.name)); err != nil {
   816→			return err
   817→		}
   818→	}
   819→	return nil
   820→}
   821→
   822→func (w *WL) fsync(f *Segment) error {
   823→	start := time.Now()
   824→	err := f.Sync()
   825→	w.metrics.fsyncDuration.Observe(time.Since(start).Seconds())
   826→	return err
   827→}
   828→
   829→// Sync forces a file sync on the current write log segment. This function is meant
   830→// to be used only on tests due to different behaviour on Operating Systems
   831→// like windows and linux.
   832→func (w *WL) Sync() error {
   833→	return w.fsync(w.segment)
   834→}
   835→
   836→// Close flushes all writes and closes active segment.
   837→func (w *WL) Close() (err error) {
   838→	w.mtx.Lock()
   839→	defer w.mtx.Unlock()
   840→
   841→	if w.closed {
   842→		return errors.New("wlog already closed")
   843→	}
   844→
   845→	if w.segment == nil {
   846→		w.closed = true
   847→		return nil
   848→	}
   849→
   850→	// Flush the last page and zero out all its remaining size.
   851→	// We must not flush an empty page as it would falsely signal
   852→	// the segment is done if we start writing to it again after opening.
   853→	if w.page.alloc > 0 {
   854→		if err := w.flushPage(true); err != nil {
   855→			return err
   856→		}
   857→	}
   858→
   859→	donec := make(chan struct{})
   860→	w.stopc <- donec
   861→	<-donec
   862→
   863→	if err = w.fsync(w.segment); err != nil {
   864→		w.logger.Error("sync previous segment", "err", err)
   865→	}
   866→	if err := w.segment.Close(); err != nil {
   867→		w.logger.Error("close previous segment", "err", err)
   868→	}
   869→
   870→	w.metrics.Unregister()
   871→	w.closed = true
   872→	return nil
   873→}
   874→
   875→// Segments returns the range [first, n] of currently existing segments.
   876→// If no segments are found, first and n are -1.
   877→func Segments(wlDir string) (first, last int, err error) {
   878→	refs, err := listSegments(wlDir)
   879→	if err != nil {
   880→		return 0, 0, err
   881→	}
   882→	if len(refs) == 0 {
   883→		return -1, -1, nil
   884→	}
   885→	return refs[0].index, refs[len(refs)-1].index, nil
   886→}
   887→
   888→type segmentRef struct {
   889→	name  string
   890→	index int
   891→}
   892→
   893→func listSegments(dir string) (refs []segmentRef, err error) {
   894→	files, err := os.ReadDir(dir)
   895→	if err != nil {
   896→		return nil, err
   897→	}
   898→	for _, f := range files {
   899→		fn := f.Name()
   900→		k, err := strconv.Atoi(fn)
   901→		if err != nil {
   902→			continue
   903→		}
   904→		refs = append(refs, segmentRef{name: fn, index: k})
   905→	}
   906→	slices.SortFunc(refs, func(a, b segmentRef) int {
   907→		return a.index - b.index
   908→	})
   909→	for i := 0; i < len(refs)-1; i++ {
   910→		if refs[i].index+1 != refs[i+1].index {
   911→			return nil, errors.New("segments are not sequential")
   912→		}
   913→	}
   914→	return refs, nil
   915→}
   916→
   917→// SegmentRange groups segments by the directory and the first and last index it includes.
   918→type SegmentRange struct {
   919→	Dir         string
   920→	First, Last int
   921→}
   922→
   923→// NewSegmentsReader returns a new reader over all segments in the directory.
   924→func NewSegmentsReader(dir string) (io.ReadCloser, error) {
   925→	return NewSegmentsRangeReader(SegmentRange{dir, -1, -1})
   926→}
   927→
   928→// NewSegmentsRangeReader returns a new reader over the given WAL segment ranges.
   929→// If first or last are -1, the range is open on the respective end.
   930→func NewSegmentsRangeReader(sr ...SegmentRange) (io.ReadCloser, error) {
   931→	var segs []*Segment
   932→
   933→	for _, sgmRange := range sr {
   934→		refs, err := listSegments(sgmRange.Dir)
   935→		if err != nil {
   936→			return nil, fmt.Errorf("list segment in dir:%v: %w", sgmRange.Dir, err)
   937→		}
   938→
   939→		for _, r := range refs {
   940→			if sgmRange.First >= 0 && r.index < sgmRange.First {
   941→				continue
   942→			}
   943→			if sgmRange.Last >= 0 && r.index > sgmRange.Last {
   944→				break
   945→			}
   946→			s, err := OpenReadSegment(filepath.Join(sgmRange.Dir, r.name))
   947→			if err != nil {
   948→				return nil, fmt.Errorf("open segment:%v in dir:%v: %w", r.name, sgmRange.Dir, err)
   949→			}
   950→			segs = append(segs, s)
   951→		}
   952→	}
   953→	return NewSegmentBufReader(segs...), nil
   954→}
   955→
   956→// segmentBufReader is a buffered reader that reads in multiples of pages.
   957→// The main purpose is that we are able to track segment and offset for
   958→// corruption reporting.  We have to be careful not to increment curr too
   959→// early, as it is used by Reader.Err() to tell Repair which segment is corrupt.
   960→// As such we pad the end of non-page align segments with zeros.
   961→type segmentBufReader struct {
   962→	buf  *bufio.Reader
   963→	segs []*Segment
   964→	cur  int // Index into segs.
   965→	off  int // Offset of read data into current segment.
   966→}
   967→
   968→func NewSegmentBufReader(segs ...*Segment) io.ReadCloser {
   969→	if len(segs) == 0 {
   970→		return &segmentBufReader{}
   971→	}
   972→
   973→	return &segmentBufReader{
   974→		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
   975→		segs: segs,
   976→	}
   977→}
   978→
   979→func NewSegmentBufReaderWithOffset(offset int, segs ...*Segment) (io.ReadCloser, error) {
   980→	if offset == 0 || len(segs) == 0 {
   981→		return NewSegmentBufReader(segs...), nil
   982→	}
   983→
   984→	sbr := &segmentBufReader{
   985→		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
   986→		segs: segs,
   987→	}
   988→	var err error
   989→	if offset > 0 {
   990→		_, err = sbr.buf.Discard(offset)
   991→	}
   992→	return sbr, err
   993→}
   994→
   995→func (r *segmentBufReader) Close() (err error) {
   996→	for _, s := range r.segs {
   997→		if e := s.Close(); e != nil {
   998→			err = e
   999→		}
  1000→	}
  1001→	return err
  1002→}
  1003→
  1004→// Read implements io.Reader.
  1005→func (r *segmentBufReader) Read(b []byte) (n int, err error) {
  1006→	if len(r.segs) == 0 {
  1007→		return 0, io.EOF
  1008→	}
  1009→
  1010→	n, err = r.buf.Read(b)
  1011→	r.off += n
  1012→
  1013→	// If we succeeded, or hit a non-EOF, we can stop.
  1014→	if err == nil || !errors.Is(err, io.EOF) {
  1015→		return n, err
  1016→	}
  1017→
  1018→	// We hit EOF; fake out zero padding at the end of short segments, so we
  1019→	// don't increment curr too early and report the wrong segment as corrupt.
  1020→	if r.off%pageSize != 0 {
  1021→		i := 0
  1022→		for ; n+i < len(b) && (r.off+i)%pageSize != 0; i++ {
  1023→			b[n+i] = 0
  1024→		}
  1025→
  1026→		// Return early, even if we didn't fill b.
  1027→		r.off += i
  1028→		return n + i, nil
  1029→	}
  1030→
  1031→	// There is no more deta left in the curr segment and there are no more
  1032→	// segments left.  Return EOF.
  1033→	if r.cur+1 >= len(r.segs) {
  1034→		return n, io.EOF
  1035→	}
  1036→
  1037→	// Move to next segment.
  1038→	r.cur++
  1039→	r.off = 0
  1040→	r.buf.Reset(r.segs[r.cur])
  1041→	return n, nil
  1042→}
  1043→
  1044→// Size computes the size of the write log.
  1045→// We do this by adding the sizes of all the files under the WAL dir.
  1046→func (w *WL) Size() (int64, error) {
  1047→	return fileutil.DirSize(w.Dir())
  1048→}
