   232→
   233→	if Type(dec.Byte()) != Series {
   234→		return nil, errors.New("invalid record type")
   235→	}
   236→	for len(dec.B) > 0 && dec.Err() == nil {
   237→		ref := storage.SeriesRef(dec.Be64())
   238→		lset := d.DecodeLabels(&dec)
