   675→	buf := encoding.Encbuf{B: b}
   676→	buf.PutByte(byte(Metadata))
   677→
   678→	for _, m := range metadata {
   679→		buf.PutUvarint64(uint64(m.Ref))
   680→
   681→		buf.PutByte(m.Type)
   682→
   683→		buf.PutUvarint(2) // num_fields: We currently have two more metadata fields, UNIT and HELP.
   684→		buf.PutUvarintStr(unitMetaName)
   685→		buf.PutUvarintStr(m.Unit)
   686→		buf.PutUvarintStr(helpMetaName)
   687→		buf.PutUvarintStr(m.Help)
   688→	}
   689→
   690→	return buf.Get()
   691→}
   692→
   693→// EncodeLabels encodes the contents of labels into buf.
   694→func EncodeLabels(buf *encoding.Encbuf, lbls labels.Labels) {
   695→	// TODO: reconsider if this function could be pushed down into labels.Labels to be more efficient.
   696→	buf.PutUvarint(lbls.Len())
   697→
   698→	lbls.Range(func(l labels.Label) {
   699→		buf.PutUvarintStr(l.Name)
   700→		buf.PutUvarintStr(l.Value)
   701→	})
   702→}
   703→
   704→// Samples appends the encoded samples to b and returns the resulting slice.
   705→func (*Encoder) Samples(samples []RefSample, b []byte) []byte {
   706→	buf := encoding.Encbuf{B: b}
   707→	buf.PutByte(byte(Samples))
   708→
   709→	if len(samples) == 0 {
   710→		return buf.Get()
   711→	}
   712→
   713→	// Store base timestamp and base reference number of first sample.
   714→	// All samples encode their timestamp and ref as delta to those.
   715→	first := samples[0]
   716→
   717→	buf.PutBE64(uint64(first.Ref))
   718→	buf.PutBE64int64(first.T)
   719→
   720→	for _, s := range samples {
   721→		buf.PutVarint64(int64(s.Ref) - int64(first.Ref))
   722→		buf.PutVarint64(s.T - first.T)
   723→		buf.PutBE64(math.Float64bits(s.V))
   724→	}
   725→	return buf.Get()
   726→}
   727→
   728→// Tombstones appends the encoded tombstones to b and returns the resulting slice.
   729→func (*Encoder) Tombstones(tstones []tombstones.Stone, b []byte) []byte {
   730→	buf := encoding.Encbuf{B: b}
   731→	buf.PutByte(byte(Tombstones))
   732→
   733→	for _, s := range tstones {
   734→		for _, iv := range s.Intervals {
   735→			buf.PutBE64(uint64(s.Ref))
   736→			buf.PutVarint64(iv.Mint)
   737→			buf.PutVarint64(iv.Maxt)
   738→		}
   739→	}
   740→	return buf.Get()
   741→}
   742→
   743→func (e *Encoder) Exemplars(exemplars []RefExemplar, b []byte) []byte {
   744→	buf := encoding.Encbuf{B: b}
   745→	buf.PutByte(byte(Exemplars))
   746→
   747→	if len(exemplars) == 0 {
   748→		return buf.Get()
   749→	}
   750→
   751→	e.EncodeExemplarsIntoBuffer(exemplars, &buf)
   752→
   753→	return buf.Get()
   754→}
   755→
   756→func (*Encoder) EncodeExemplarsIntoBuffer(exemplars []RefExemplar, buf *encoding.Encbuf) {
   757→	// Store base timestamp and base reference number of first sample.
   758→	// All samples encode their timestamp and ref as delta to those.
   759→	first := exemplars[0]
   760→
   761→	buf.PutBE64(uint64(first.Ref))
   762→	buf.PutBE64int64(first.T)
   763→
   764→	for _, ex := range exemplars {
   765→		buf.PutVarint64(int64(ex.Ref) - int64(first.Ref))
   766→		buf.PutVarint64(ex.T - first.T)
   767→		buf.PutBE64(math.Float64bits(ex.V))
   768→		EncodeLabels(buf, ex.Labels)
   769→	}
   770→}
   771→
   772→func (*Encoder) MmapMarkers(markers []RefMmapMarker, b []byte) []byte {
   773→	buf := encoding.Encbuf{B: b}
   774→	buf.PutByte(byte(MmapMarkers))
   775→
   776→	for _, s := range markers {
   777→		buf.PutBE64(uint64(s.Ref))
   778→		buf.PutBE64(uint64(s.MmapRef))
   779→	}
   780→
   781→	return buf.Get()
   782→}
   783→
   784→func (*Encoder) HistogramSamples(histograms []RefHistogramSample, b []byte) ([]byte, []RefHistogramSample) {
   785→	buf := encoding.Encbuf{B: b}
   786→	buf.PutByte(byte(HistogramSamples))
   787→
   788→	if len(histograms) == 0 {
   789→		return buf.Get(), nil
   790→	}
   791→	var customBucketHistograms []RefHistogramSample
   792→
   793→	// Store base timestamp and base reference number of first histogram.
   794→	// All histograms encode their timestamp and ref as delta to those.
   795→	first := histograms[0]
   796→	buf.PutBE64(uint64(first.Ref))
   797→	buf.PutBE64int64(first.T)
   798→
   799→	for _, h := range histograms {
   800→		if h.H.UsesCustomBuckets() {
   801→			customBucketHistograms = append(customBucketHistograms, h)
   802→			continue
   803→		}
   804→		buf.PutVarint64(int64(h.Ref) - int64(first.Ref))
   805→		buf.PutVarint64(h.T - first.T)
   806→
   807→		EncodeHistogram(&buf, h.H)
   808→	}

