    15→package wlog
    16→
    17→import (
    18→	"encoding/binary"
    19→	"errors"
    20→	"fmt"
    21→	"hash/crc32"
    22→	"io"
    23→
    24→	"github.com/prometheus/prometheus/util/compression"
    25→)
    26→
    27→// Reader reads WAL records from an io.Reader.
    28→type Reader struct {
    29→	rdr io.Reader
    30→	err error
    31→	rec []byte
    32→
    33→	precomprBuf []byte
    34→	decBuf      compression.DecodeBuffer
    35→	buf         [pageSize]byte
    36→	total       int64   // Total bytes processed.
    37→	curRecTyp   recType // Used for checking that the last record is not torn.
    38→}
    39→
    40→// NewReader returns a new reader.
    41→func NewReader(r io.Reader) *Reader {
    42→	return &Reader{rdr: r, decBuf: compression.NewSyncDecodeBuffer()}
    43→}
    44→
    45→// Next advances the reader to the next records and returns true if it exists.
    46→// It must not be called again after it returned false.
    47→func (r *Reader) Next() bool {
    48→	err := r.nextNew()
    49→	if err != nil && errors.Is(err, io.EOF) {
    50→		// The last WAL segment record shouldn't be torn(should be full or last).
    51→		// The last record would be torn after a crash just before
    52→		// the last record part could be persisted to disk.
    53→		if r.curRecTyp == recFirst || r.curRecTyp == recMiddle {
    54→			r.err = errors.New("last record is torn")
    55→		}
    56→		return false
    57→	}
    58→	r.err = err
    59→	return r.err == nil
    60→}
    61→
    62→func (r *Reader) nextNew() (err error) {
    63→	// We have to use r.buf since allocating byte arrays here fails escape
    64→	// analysis and ends up on the heap, even though it seemingly should not.
    65→	hdr := r.buf[:recordHeaderSize]
    66→	buf := r.buf[recordHeaderSize:]
    67→
    68→	r.precomprBuf = r.precomprBuf[:0]
    69→
    70→	i := 0
    71→	for {
    72→		if _, err = io.ReadFull(r.rdr, hdr[:1]); err != nil {
    73→			return fmt.Errorf("read first header byte: %w", err)
    74→		}
    75→		r.total++
    76→		r.curRecTyp = recTypeFromHeader(hdr[0])
    77→
