    85→		// Gobble up zero bytes.
    86→		if r.curRecTyp == recPageTerm {
    87→			// recPageTerm is a single byte that indicates the rest of the page is padded.
    88→			// If it's the first byte in a page, buf is too small and
    89→			// needs to be resized to fit pageSize-1 bytes.
    90→			buf = r.buf[1:]
