    93→			// to a page boundary.
    94→			// It's not strictly necessary but may catch sketchy state early.
    95→			k := pageSize - (r.total % pageSize)
    96→			if k == pageSize {
    97→				continue // Initial 0 byte was last page byte.
    98→			}
    99→			n, err := io.ReadFull(r.rdr, buf[:k])
   100→			if err != nil {
   101→				return fmt.Errorf("read remaining zeros: %w", err)
   102→			}
   103→			r.total += int64(n)
   104→
   105→			for _, c := range buf[:k] {
   106→				if c != 0 {
   107→					return errors.New("unexpected non-zero byte in padded page")
   108→				}
   109→			}
   110→			continue
   111→		}
   112→		n, err := io.ReadFull(r.rdr, hdr[1:])
   113→		if err != nil {
   114→			return fmt.Errorf("read remaining header: %w", err)
   115→		}
   116→		r.total += int64(n)
   117→
   118→		var (
   119→			length = binary.BigEndian.Uint16(hdr[1:])
   120→			crc    = binary.BigEndian.Uint32(hdr[3:])
   121→		)
   122→
   123→		if length > pageSize-recordHeaderSize {
   124→			return fmt.Errorf("invalid record size %d", length)
   125→		}
   126→		n, err = io.ReadFull(r.rdr, buf[:length])
   127→		if err != nil {
   128→			return err
   129→		}
   130→		r.total += int64(n)
   131→
   132→		if n != int(length) {
   133→			return fmt.Errorf("invalid size: expected %d, got %d", length, n)
   134→		}
   135→		if c := crc32.Checksum(buf[:length], castagnoliTable); c != crc {
   136→			return fmt.Errorf("unexpected checksum %x, expected %x", c, crc)
   137→		}
   138→		if err := validateRecord(r.curRecTyp, i); err != nil {
   139→			return err
   140→		}
   141→
   142→		r.precomprBuf = append(r.precomprBuf, buf[:length]...)
   143→		if r.curRecTyp == recLast || r.curRecTyp == recFull {
   144→			r.rec, err = compression.Decode(compr, r.precomprBuf, r.decBuf)
   145→			return err
   146→		}
   147→
   148→		// Only increment i for non-zero records since we use it
   149→		// to determine valid content record sequences.
   150→		i++
   151→	}
   152→}
