    28→// repairBadIndexVersion repairs an issue in index and meta.json persistence introduced in
    29→// commit 129773b41a565fde5156301e37f9a87158030443.
    30→func repairBadIndexVersion(logger *slog.Logger, dir string) error {
    31→	// All blocks written by Prometheus 2.1 with a meta.json version of 2 are affected.
    32→	// We must actually set the index file version to 2 and revert the meta.json version back to 1.
    33→	dirs, err := blockDirs(dir)
    34→	if err != nil {
    35→		return fmt.Errorf("list block dirs in %q: %w", dir, err)
    36→	}
    37→
    38→	tmpFiles := make([]string, 0, len(dirs))
    39→	defer func() {
    40→		for _, tmp := range tmpFiles {
    41→			if err := os.RemoveAll(tmp); err != nil {
    42→				logger.Error("remove tmp file", "err", err.Error())
    43→			}
    44→		}
    45→	}()
    46→
    47→	for _, d := range dirs {
    48→		meta, err := readBogusMetaFile(d)
    49→		if err != nil {
    50→			logger.Error("failed to read meta.json for a block during repair process; skipping", "dir", d, "err", err)
    51→			continue
    52→		}
    53→		if meta.Version == metaVersion1 {
    54→			logger.Info(
    55→				"Found healthy block",
    56→				"mint", meta.MinTime,
    57→				"maxt", meta.MaxTime,
    58→				"ulid", meta.ULID,
    59→			)
    60→			continue
    61→		}
    62→		logger.Info(
    63→			"Fixing broken block",
    64→			"mint", meta.MinTime,
    65→			"maxt", meta.MaxTime,
    66→			"ulid", meta.ULID,
    67→		)
    68→
    69→		repl, err := os.Create(filepath.Join(d, "index.repaired"))
    70→		if err != nil {
    71→			return fmt.Errorf("create index.repaired for block dir: %v: %w", d, err)
    72→		}
    73→		tmpFiles = append(tmpFiles, repl.Name())
    74→
    75→		broken, err := os.Open(filepath.Join(d, indexFilename))
    76→		if err != nil {
    77→			return fmt.Errorf("open broken index for block dir: %v: %w", d, err)
    78→		}
    79→		if _, err := io.Copy(repl, broken); err != nil {
    80→			return fmt.Errorf("copy content of index to index.repaired for block dir: %v: %w", d, err)
    81→		}
    82→
    83→		// Set the 5th byte to 2 to indicate the correct file format version.
    84→		if _, err := repl.WriteAt([]byte{2}, 4); err != nil {
    85→			errs := []error{
    86→				fmt.Errorf("rewrite of index.repaired for block dir: %v: %w", d, err),
    87→			}
    88→			if err := repl.Close(); err != nil {
    89→				errs = append(errs, fmt.Errorf("close: %w", err))
    90→			}
    91→			return errors.Join(errs...)
    92→		}
    93→		if err := repl.Sync(); err != nil {
    94→			errs := []error{
    95→				fmt.Errorf("sync of index.repaired for block dir: %v: %w", d, err),
    96→			}
    97→			if err := repl.Close(); err != nil {
    98→				errs = append(errs, fmt.Errorf("close: %w", err))
    99→			}
   100→			return errors.Join(errs...)
   101→		}
   102→		if err := repl.Close(); err != nil {
   103→			return fmt.Errorf("close repaired index for block dir: %v: %w", d, err)
   104→		}
